using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestDbContextFactory
{
    public static SchoolContext Create(string dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;

        var context = new SchoolContext(options);
        context.Database.EnsureCreated();
        return context;
    }

    public static SchoolContext CreateWithData(string dbName = null)
    {
        var context = Create(dbName);
        SeedData(context);
        return context;
    }

    private static void SeedData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            ID = 1,
            LastName = "Abercrombie",
            FirstMidName = "Kim",
            HireDate = DateTime.Parse("1995-03-11"),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Smith 17" }
        };

        var instructor2 = new Instructor
        {
            ID = 2,
            LastName = "Fakhouri",
            FirstMidName = "Fadi",
            HireDate = DateTime.Parse("2002-07-06"),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.AddRange(instructor1, instructor2);

        var dept1 = new Department
        {
            DepartmentID = 1,
            Name = "English",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 1
        };

        var dept2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01"),
            InstructorID = 2
        };

        context.Departments.AddRange(dept1, dept2);

        var course1 = new Course
        {
            CourseID = 1050,
            Title = "Chemistry",
            Credits = 3,
            DepartmentID = 1,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        var course2 = new Course
        {
            CourseID = 4022,
            Title = "Microeconomics",
            Credits = 3,
            DepartmentID = 2,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Courses.AddRange(course1, course2);

        var student1 = new Student
        {
            ID = 10,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.Parse("2010-09-01"),
            Enrollments = new List<Enrollment>()
        };

        var student2 = new Student
        {
            ID = 11,
            LastName = "Alonso",
            FirstMidName = "Meredith",
            EnrollmentDate = DateTime.Parse("2012-09-01"),
            Enrollments = new List<Enrollment>()
        };

        var student3 = new Student
        {
            ID = 12,
            LastName = "Anand",
            FirstMidName = "Arturo",
            EnrollmentDate = DateTime.Parse("2013-09-01"),
            Enrollments = new List<Enrollment>()
        };

        context.Students.AddRange(student1, student2, student3);

        var enrollment1 = new Enrollment { EnrollmentID = 1, CourseID = 1050, StudentID = 10, Grade = Grade.A };
        var enrollment2 = new Enrollment { EnrollmentID = 2, CourseID = 4022, StudentID = 10, Grade = Grade.C };
        var enrollment3 = new Enrollment { EnrollmentID = 3, CourseID = 1050, StudentID = 11, Grade = Grade.B };

        context.Enrollments.AddRange(enrollment1, enrollment2, enrollment3);

        // CourseAssignments
        var ca1 = new CourseAssignment { InstructorID = 1, CourseID = 1050 };
        context.CourseAssignments.Add(ca1);

        context.SaveChanges();
    }
}

