    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var items = Enumerable.Empty<int>().AsQueryable();

        var result = PaginatedList<int>.Create(items, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
