namespace ContosoUniversity.Tests;

public class SchoolContextTests
{
    [Fact]
    public void CanCreateDatabase()
    {
        using var context = TestDbContextFactory.Create();
        Assert.True(context.Database.EnsureCreated());
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        using var context = TestDbContextFactory.Create();
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.Equal("Test", retrieved.LastName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        using var context = TestDbContextFactory.Create();
        var dept = new Department
        {
            Name = "Science",
            Budget = 100000,
            StartDate = DateTime.Now
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 101,
            Title = "Intro to Science",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.Include(c => c.Department).First();
        Assert.Equal("Intro to Science", retrieved.Title);
        Assert.Equal("Science", retrieved.Department.Name);
    }

    [Fact]
    public void CanAddEnrollment_WithRelationships()
    {
        using var context = TestDbContextFactory.Create();

        var student = new Student { LastName = "S", FirstMidName = "T", EnrollmentDate = DateTime.Now };
        context.Students.Add(student);

        var dept = new Department { Name = "D", Budget = 1000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 200, Title = "C", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var enrollment = new Enrollment { CourseID = course.CourseID, StudentID = student.ID, Grade = Grade.A };
        context.Enrollments.Add(enrollment);
        context.SaveChanges();

        var retrieved = context.Enrollments.Include(e => e.Student).Include(e => e.Course).First();
        Assert.Equal("S", retrieved.Student.LastName);
        Assert.Equal("C", retrieved.Course.Title);
        Assert.Equal(Grade.A, retrieved.Grade);
    }

    [Fact]
    public void CourseAssignment_HasCompositeKey()
    {
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor
        {
            LastName = "I",
            FirstMidName = "T",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);

        var dept = new Department { Name = "D", Budget = 1000, StartDate = DateTime.Now };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course { CourseID = 300, Title = "C", Credits = 3, DepartmentID = dept.DepartmentID };
        context.Courses.Add(course);
        context.SaveChanges();

        var ca = new CourseAssignment { InstructorID = instructor.ID, CourseID = course.CourseID };
        context.CourseAssignments.Add(ca);
        context.SaveChanges();

        var retrieved = context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.NotNull(retrieved);
    }

    [Fact]
    public void Instructor_CanHaveOfficeAssignment()
    {
        using var context = TestDbContextFactory.Create();

        var instructor = new Instructor
        {
            LastName = "Office",
            FirstMidName = "Test",
            HireDate = DateTime.Now,
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { Location = "Room 101" }
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.Include(i => i.OfficeAssignment)
            .First(i => i.LastName == "Office");
        Assert.Equal("Room 101", retrieved.OfficeAssignment.Location);
    }

    [Fact]
    public void Person_FullName_ConcatenatesLastAndFirst()
    {
        var student = new Student { LastName = "Smith", FirstMidName = "John" };
        Assert.Equal("Smith, John", student.FullName);
    }

    [Fact]
    public void Department_CanHaveNullAdministrator()
    {
        using var context = TestDbContextFactory.Create();

        var dept = new Department
        {
            Name = "NoAdmin",
            Budget = 50000,
            StartDate = DateTime.Now,
            InstructorID = null
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var retrieved = context.Departments.First(d => d.Name == "NoAdmin");
        Assert.Null(retrieved.InstructorID);
    }
}
