using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestDbContextFactory.CreateWithData();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewResult_WithPaginatedList()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    [Fact]
    public void Index_SortsByNameDescending()
    {
        var result = _controller.Index("name_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model.First().LastName);
    }

    [Fact]
    public void Index_SortsByDateAscending()
    {
        var result = _controller.Index("Date", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model.First().LastName);
    }

    [Fact]
    public void Index_SortsByDateDescending()
    {
        var result = _controller.Index("date_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Anand", model.First().LastName);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal("Alexander", model.First().LastName);
    }

    [Fact]
    public void Index_FiltersBySearchString()
    {
        var result = _controller.Index(null, null, "Alexander", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alexander", model.First().LastName);
    }

    [Fact]
    public void Index_SearchByFirstName()
    {
        var result = _controller.Index(null, null, "Meredith", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
        Assert.Equal("Alonso", model.First().LastName);
    }

    [Fact]
    public void Index_UsesCurrentFilter_WhenSearchStringIsNull()
    {
        var result = _controller.Index(null, "Alexander", null, 1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsPageTo1_WhenSearchStringIsProvided()
    {
        var result = _controller.Index(null, null, "A", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.Equal("A", _controller.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Details_ReturnsNotFound_WhenIdIsNull()
    {
        var result = _controller.Details(null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Details_ReturnsViewResult_WithStudent()
    {
        var result = _controller.Details(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Details_IncludesEnrollments()
    {
        var result = _controller.Details(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(2, model.Enrollments.Count);
    }

    [Fact]
    public void Create_Get_ReturnsViewResult_WithNewStudent()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        var result = _controller.Create(student);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Create_Post_ValidStudent_AddsToDatabase()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        _controller.Create(student);

        Assert.Equal(4, _context.Students.Count());
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_DefaultDate_ReturnsView()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_TooEarly_ReturnsView()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(1752, 1, 1)
        };

        var result = _controller.Create(student);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Get_ReturnsNotFound_WhenIdIsNull()
    {
        var result = _controller.Edit((int?)null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ReturnsNotFound_WhenStudentDoesNotExist()
    {
        var result = _controller.Edit(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ReturnsViewResult_WithStudent()
    {
        var result = _controller.Edit(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        var student = _context.Students.AsNoTracking().First(s => s.ID == 10);
        student.LastName = "UpdatedName";
        student.EnrollmentDate = DateTime.Parse("2010-09-01");

        var result = _controller.Edit(student);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidEnrollmentDate_ReturnsView()
    {
        var student = new Student
        {
            ID = 10,
            LastName = "Alexander",
            FirstMidName = "Carson",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Delete_Get_ReturnsNotFound_WhenIdIsNull()
    {
        var result = _controller.Delete(null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ReturnsNotFound_WhenStudentDoesNotExist()
    {
        var result = _controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ReturnsViewResult_WithStudent()
    {
        var result = _controller.Delete(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void DeleteConfirmed_RemovesStudent_AndRedirects()
    {
        var result = _controller.DeleteConfirmed(10);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(2, _context.Students.Count());
    }
}

