using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;
using System.Text;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;
    private readonly string _tempPath;

    public CoursesControllerTests()
    {
        _context = TestDbContextFactory.CreateWithData();
        _envMock = new Mock<IWebHostEnvironment>();
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _tempPath = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
        Directory.CreateDirectory(_tempPath);
        _envMock.Setup(e => e.WebRootPath).Returns(_tempPath);
        _envMock.Setup(e => e.ContentRootPath).Returns(_tempPath);
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
        if (Directory.Exists(_tempPath))
        {
            try { Directory.Delete(_tempPath, true); } catch { }
        }
    }

    [Fact]
    public void Index_ReturnsViewResult_WithListOfCourses()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Equal(2, model.Count);
    }

    [Fact]
    public void Details_ReturnsBadRequest_WhenIdIsNull()
    {
        var result = _controller.Details(null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Details_ReturnsViewResult_WithCourse()
    {
        var result = _controller.Details(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Create_Get_ReturnsViewResult()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.IsType<Course>(viewResult.Model);
    }

    [Fact]
    public void Create_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Equal(3, _context.Courses.Count());
    }

    [Fact]
    public void Create_Post_ValidCourse_WithValidImage_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 8888,
            Title = "Image Course",
            Credits = 2,
            DepartmentID = 1
        };

        var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 1024);

        var result = _controller.Create(course, fileMock.Object);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.NotNull(_context.Courses.Find(8888).TeachingMaterialImagePath);
    }

    [Fact]
    public void Create_Post_InvalidExtension_ReturnsView()
    {
        var course = new Course
        {
            CourseID = 7777,
            Title = "Bad File Course",
            Credits = 2,
            DepartmentID = 1
        };

        var fileMock = CreateMockFormFile("test.exe", "application/exe", 1024);

        var result = _controller.Create(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_FileTooLarge_ReturnsView()
    {
        var course = new Course
        {
            CourseID = 6666,
            Title = "Large File Course",
            Credits = 2,
            DepartmentID = 1
        };

        var fileMock = CreateMockFormFile("test.jpg", "image/jpeg", 6 * 1024 * 1024);

        var result = _controller.Create(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 5555, DepartmentID = 1 };

        var result = _controller.Create(course, null);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
    {
        var result = _controller.Edit((int?)null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ReturnsNotFound_WhenCourseDoesNotExist()
    {
        var result = _controller.Edit(9999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_Get_ReturnsViewResult_WithCourse()
    {
        var result = _controller.Edit(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Edit_Post_ValidCourse_NoImage_RedirectsToIndex()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
        course.Title = "Updated Chemistry";

        var result = _controller.Edit(course, null);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Edit_Post_InvalidExtension_ReturnsView()
    {
        var course = _context.Courses.AsNoTracking().First(c => c.CourseID == 1050);
        var fileMock = CreateMockFormFile("test.exe", "application/exe", 1024);

        var result = _controller.Edit(course, fileMock.Object);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, DepartmentID = 1 };

        var result = _controller.Edit(course, null);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
    {
        var result = _controller.Delete(null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ReturnsViewResult_WithCourse()
    {
        var result = _controller.Delete(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void DeleteConfirmed_RemovesCourse_AndRedirects()
    {
        var result = _controller.DeleteConfirmed(1050);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Null(_context.Courses.Find(1050));
    }

    [Fact]
    public void DeleteConfirmed_RemovesAssociatedImage()
    {
        // Set up a course with an image file
        var course = _context.Courses.Find(1050);
        var uploadsDir = Path.Combine(_tempPath, "Uploads", "TeachingMaterials");
        Directory.CreateDirectory(uploadsDir);
        var imagePath = Path.Combine(uploadsDir, "test_image.jpg");
        File.WriteAllText(imagePath, "fake image");
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/test_image.jpg";
        _context.SaveChanges();

        _controller.DeleteConfirmed(1050);

        Assert.False(File.Exists(imagePath));
    }

    private Mock<IFormFile> CreateMockFormFile(string fileName, string contentType, long length)
    {
        var fileMock = new Mock<IFormFile>();
        var content = new byte[Math.Min(length, 1024)];
        var ms = new MemoryStream(content);
        fileMock.Setup(f => f.FileName).Returns(fileName);
        fileMock.Setup(f => f.Length).Returns(length);
        fileMock.Setup(f => f.ContentType).Returns(contentType);
        fileMock.Setup(f => f.OpenReadStream()).Returns(ms);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()))
            .Callback<Stream>(s => ms.CopyTo(s));
        return fileMock;
    }
}

