using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using Xunit;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestDbContextFactory.CreateWithData();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsViewResult_WithInstructorIndexData()
    {
        var result = _controller.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_PopulatesCourses()
    {
        var result = _controller.Index(1, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithInstructorAndCourseId_PopulatesEnrollments()
    {
        var result = _controller.Index(1, 1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
    }

    [Fact]
    public void Details_ReturnsBadRequest_WhenIdIsNull()
    {
        var result = _controller.Details(null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Details_ReturnsNotFound_WhenInstructorDoesNotExist()
    {
        var result = _controller.Details(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Details_ReturnsViewResult_WithInstructor()
    {
        var result = _controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Create_Get_ReturnsViewResult_WithInstructor()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
    }

    [Fact]
    public void Create_Post_ValidInstructor_NoCourses_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "NewInstructor",
            FirstMidName = "Test",
            HireDate = DateTime.Parse("2023-01-15")
        };

        var result = _controller.Create(instructor, null);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Create_Post_ValidInstructor_WithCourses_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "CourseInstructor",
            FirstMidName = "With",
            HireDate = DateTime.Parse("2023-01-15")
        };

        var result = _controller.Create(instructor, new[] { "1050" });

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
    }

    [Fact]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            HireDate = DateTime.Parse("2023-01-15"),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_Get_ReturnsBadRequest_WhenIdIsNull()
    {
        var result = _controller.Edit((int?)null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Edit_Get_ReturnsViewResult_WithInstructor()
    {
        var result = _controller.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Delete_Get_ReturnsBadRequest_WhenIdIsNull()
    {
        var result = _controller.Delete(null);

        var statusCodeResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusCodeResult.StatusCode);
    }

    [Fact]
    public void Delete_Get_ReturnsNotFound_WhenInstructorDoesNotExist()
    {
        var result = _controller.Delete(999);

        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Delete_Get_ReturnsViewResult_WithInstructor()
    {
        var result = _controller.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructor_AndRedirects()
    {
        var result = _controller.DeleteConfirmed(2);

        var redirect = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirect.ActionName);
        Assert.Null(_context.Instructors.Find(2));
    }

    [Fact]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        // Instructor 2 is admin of Math dept
        _controller.DeleteConfirmed(2);

        var dept = _context.Departments.Find(2);
        Assert.Null(dept.InstructorID);
    }
}

